def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf if item != 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        complex_penalty = 0.0
        adj_factor = 1.0
        decay = 1.0
        extension = 0.0
        if item == 0:
            priorities[i] = 0
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for k in range(1, 10):
                complex_penalty += ((-1) ** k) * (ratio ** (2 * k)) / (k ** 2 + 1)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j + 1))
            score = (ratio ** 6) / 3 + complex_penalty
            if item > capacity * 5:
                score *= 4
            else:
                score *= 3
            priorities[i] = score * decay
        elif 3 < ratio <= 4:
            for x in range(1, 12):
                sign = -1 if x % 2 == 0 else 1
                score += sign * (ratio ** x) / (x + 1)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 2))
            score = abs(score) * decay * 15
            priorities[i] = score
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 20):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 7)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 5)
                else:
                    temp += (ratio ** p) / (p * 4)
            if ratio < 2.25:
                multiplier = 20
            elif ratio < 2.75:
                multiplier = 14
            else:
                multiplier = 9
            score = abs(temp) * multiplier
            if ratio > 2.9:
                ext_val = 0
                for m in range(1, 10):
                    ext_val += (ratio ** m) / (m * 2 + 3)
                score += ext_val * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            for p in range(1, 25):
                if p % 5 == 0:
                    temp_score -= (ratio ** p) / (p * 6)
                elif p % 4 == 0:
                    temp_score += (ratio ** p) / (p * 3)
                elif p % 3 == 0:
                    temp_score -= (ratio ** p) / (p * 4)
                else:
                    temp_score += (ratio ** p) / (p * 5)
            if ratio < 1.3:
                multiplier = 28
            elif ratio < 1.6:
                multiplier = 20
            elif ratio < 1.85:
                multiplier = 12
            else:
                multiplier = 7
            score = abs(temp_score) * multiplier
            if 1.8 < ratio < 1.95:
                extra = 0
                for n in range(1, 12):
                    extra += (ratio ** n) / (n + 2)
                score += extra * 2.5
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 30):
                if p % 6 == 0:
                    temp_score += (ratio ** p) / (p * 2)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * 3)
                elif p % 3 == 0:
                    temp_score += (ratio ** p) / (p * 4)
                else:
                    temp_score -= (ratio ** p) / (p * 5)
            if ratio < 0.1:
                multiplier = 40
            elif ratio < 0.3:
                multiplier = 25
            elif ratio < 0.5:
                multiplier = 18
            elif ratio < 0.7:
                multiplier = 12
            else:
                multiplier = 8
            score = abs(temp_score) * multiplier
            if 0.75 < ratio < 0.95:
                extra_penalties = 0
                for n in range(1, 10):
                    extra_penalties += (ratio ** n) / (n + 1)
                score += extra_penalties * 3
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    for i in range(len(priorities)):
        if priorities[i] != np.inf and bins[i] > 0:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + z / (bins[i] + z))
            priorities[i] *= factor
        else:
            priorities[i] = np.inf
    for i in range(len(priorities)):
        if priorities[i] != np.inf:
            augment = 0.0
            for q in range(1, 5):
                augment += np.sin(item * q) / (q + bins[i] + 1)
            priorities[i] += abs(augment) * 5
    return priorities
